const { decodeFunctionData, parseAbi } = require('viem');

const abi = parseAbi([
  'function listAgent(string agentId, uint256 price, string metadataUri)'
]);

const input = '';

async function main() {
  try {
    const decoded = decodeFunctionData({
      abi,
      data: input
    });
    console.log('Decoded Function Call:', decoded);
  } catch (err) {
    console.error(err);
  }
}

main();
